def is_palindrome(text):
    cleaned = text.lower().replace(" ", "")
    return cleaned == cleaned[::-1]


def is_number_palindrome(number):
    text = str(number)
    return text == text[::-1]


words = ["kayak", "araba", "anna", "elma", "a man a plan a canal panama"]

print("Kelime testleri:")
for word in words:
    print(f"'{word}' palindrome mu: {is_palindrome(word)}")

print("\nSayi testleri:")
numbers = [12321, 12345, 1001, 5]
for num in numbers:
    print(f"{num} palindrome mu: {is_number_palindrome(num)}")

# Bir cumledeki palindrome kelimeleri bulma
sentence = "anna ve oto kelimeleri palindrome ama python degil"
print("\nCumledeki palindrome kelimeler:")
for word in sentence.split():
    if is_palindrome(word) and len(word) > 1:
        print("-", word)
